mapper.select:
SELECT dept_id, dept_name, dept_head, location, emp_count, use_yn, created_at, updated_at
FROM departments
WHERE dept_id = #{deptId}

mapper.update:
UPDATE departments
dept_name = #{deptName}, dept_head = #{deptHead}, location = #{location}, use_yn = #{useYn}, updated_at = CURRENT_TIMESTAMP
WHERE dept_id = #{deptId}
